import{_ as t,o as e,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F05: 應收帳款品質與收款天數 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3680_家登/20260509/F05_應收帳款品質與收款天數.md","filePath":"審計報告庫/財務審計/3680_家登/20260509/F05_應收帳款品質與收款天數.md"}'),r={name:"審計報告庫/財務審計/3680_家登/20260509/F05_應收帳款品質與收款天數.md"};function o(n,a,s,h,d,c){return e(),l("div",null,[...a[0]||(a[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f05-應收帳款品質與收款天數-財務審計專家報告" tabindex="-1">F05: 應收帳款品質與收款天數 - 財務審計專家報告 <a class="header-anchor" href="#f05-應收帳款品質與收款天數-財務審計專家報告" aria-label="Permalink to &quot;F05: 應收帳款品質與收款天數 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>應收帳款規模與 DSO 變動分析，判定是否存在客戶拖欠或虛增營收風險。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：DSO 62→82 天仍在授信範圍。AR 成長從 +71.5% 收斂至 +3.8%。最高風險在於最大客戶 AR 佔比從 16% 飆至 43%，單點曝險劇增。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：2025 Q4</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>DSO 天數</strong>：93（2022）→ 62（2023）→ 86（2024）→ 82（2025），2025 年較 2024 年改善 4 天</li><li><strong>AR 淨額</strong>：10.77 億→ 8.85 億→ 15.19 億→ 15.76 億</li><li><strong>AR / 營收比</strong>：25.4% → 17.0% → 23.4% → 22.3%</li><li><strong>帳齡結構</strong>：2025 年 1-90 天佔 90.4%（2024 年 86.7%），91-180 天佔 7.5%（改善），逾期 &gt;180 天僅 2.1%</li><li><strong>診斷見解</strong>：AR 品質良好——帳齡結構健康、呆帳率僅 0.44%。但最大客戶佔 AR 43%（2024 年 16%）的集中度跳升是重要警訊，需關注客戶 A（台積電）是否集中議價並拉長付款週期。DSO 82 天處在授信區間上緣但未超標。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、收款天數-dso-實測與趨勢" tabindex="-1">一、收款天數 DSO 實測與趨勢 <a class="header-anchor" href="#一、收款天數-dso-實測與趨勢" aria-label="Permalink to &quot;一、收款天數 DSO 實測與趨勢&quot;">​</a></h3><ul><li><strong>核心重點</strong>：DSO 從 2023 年 62 天（最佳）反彈至 2024 年 86 天（最差），2025 年改善至 82 天。4 年加權平均 DSO 約 81 天。</li><li><strong>深度見解</strong>：2023 年 DSO 驟降得益於應收帳款從 10.77 億降至 8.85 億（同期營收成長 22.4%），顯示 2023 年收款效率極佳。2024 年 DSO 反彈主因營收 +24.6% 的同時 AR 暴增 71.5% 至 15.19 億——AR 成長速度是營收的 2.9 倍，屬於 AR/Revenue 背離警訊。2025 年 AR 成長僅 +3.8%（營收 +8.9%），AR/Revenue 比率從 23.4% 降至 22.3%，背離已修正。</li></ul><h3 id="二、帳齡結構與呆帳風險評估" tabindex="-1">二、帳齡結構與呆帳風險評估 <a class="header-anchor" href="#二、帳齡結構與呆帳風險評估" aria-label="Permalink to &quot;二、帳齡結構與呆帳風險評估&quot;">​</a></h3><ul><li><strong>核心重點</strong>：逾期 &gt;90 天 AR 佔總額 9.6%（2025），低於 2024 年的 13.3%。預期信用損失率極低：1-90 天 0.24%、91-180 天 0.87%，全年備抵損失僅 697 萬（佔 AR 0.44%）。</li><li><strong>深度見解</strong>：0.44% 的呆帳率顯示收款幾乎無實際損失，反映客戶 A（台積電）等頂級客戶的極低違約風險。但備抵提列率偏低，若客戶信用條件惡化，可能需要一次性增提。2025 年實際沖銷僅 99 萬，歷史信用損失極小。</li></ul><h3 id="三、客戶集中度分析" tabindex="-1">三、客戶集中度分析 <a class="header-anchor" href="#三、客戶集中度分析" aria-label="Permalink to &quot;三、客戶集中度分析&quot;">​</a></h3><ul><li><strong>核心重點</strong>：最大客戶應收帳款佔比從 2024 年 16% 跳升至 2025 年 43%。同期該客戶營收佔比從 34.6% 升至 45.25%。</li><li><strong>深度見解</strong>：43% 的 AR 集中在單一客戶（台積電），雖然該客戶違約風險趨近於零，但如此集中度意味著付款條件的任何微調（如從 60 天延至 90 天）都會直接拉高 DSO。2024 年 AR 暴增 +71.5% 即可能反映此現象。隨著台積電 2nm 量產對光罩盒需求擴大，AR 集中度短期內恐難下降。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析（Skepticism Mandate） <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析（Skepticism Mandate）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>AR 集中度 43% 的系統性風險</strong>：從 16% 跳升至 43%，絕對值約 2.5→6.8 億。單一客戶佔 AR 近半，任何付款週期調整都將衝擊營運資金，FCF 為負下更增<strong>壓力</strong>。</li><li><strong>DSO 82 天仍處高位</strong>：相比 2023 年 62 天高出 32%，EUV 獨佔地位未換來更好收款條件。</li><li><strong>2024 年 AR 暴增 6.34 億</strong>的資金佔用需時間消化，存量 AR 15.76 億使 DSO 難回 62 天。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>帳齡結構健康</strong>：90.4% AR 在 90 天內，客戶為頂級半導體廠，違約風險極低。</li><li><strong>DSO 已見改善拐點</strong>：86→82 天，AR 成長已慢於營收成長。</li><li><strong>壞帳歷史優異</strong>：實際沖銷 2025 年僅 99 萬。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>AR 品質帳面健康但集中度風險顯著。若 2026 年 AR 佔比維持 22% 以下且 DSO 續降至 75 天以下，則改善趨勢確立。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (receivable_check 3680 2022 2025)</li><li>原始數據：FinMind TaiwanStockBalanceSheet (AccountsReceivableNet) + TaiwanStockMonthRevenue</li><li>年報：2025_Q4_3680_合併.pdf（第 119-120 頁應收帳款附註）</li><li>查詢參數：stock_id=3680, start=2022-01-01, end=2025-12-31</li><li>數據查詢日期：2026-05-09</li></ul>',24)])])}const g=t(r,[["render",o]]);export{_ as __pageData,g as default};
